var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"도, 도망쳐! 침식체다!","JPN":"に、逃げろ！侵食体だ！","ENG":"R-run! It's a C.O.!","TWN":"快、快逃！是侵蝕體！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아앙, 엄마! 아빠! 어딨어?","JPN":"うわあああん、ママ！パパ！どこにいるの？","ENG":"Wahhhh, Mommy! Daddy! Where are you?","TWN":"嗚啊啊啊啊，媽媽！爸爸！你們在哪？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 안돼! 우리 집이......! 저기엔 내 아내와 아들이......!","JPN":"ダ、ダメだ！俺の家が……！あそこには妻と息子が……！","ENG":"N-no! My house! My wife, my son!","TWN":"不、不要！那是我家啊……！我的老婆和兒子都在那裡……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체들만 아니었어도...... 내 친구들은 죽지 않았을 거야......","JPN":"侵食体さえいなければ……、友が死ぬことはなかった……","ENG":"If it wasn't for the C.O.... my friends would have never died...","TWN":"要不是侵蝕體……我的朋友就根本不會死……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체 때문에 고향이 쑥대밭이 됐어. 이제 다 끝났다고!","JPN":"侵食体のせいで故郷が廃墟になった。すべて終わったんだ！","ENG":"My hometown was devastated because of the C.O. It's all over now!","TWN":"因為侵蝕體，我的家鄉成了一片廢墟，一切都結束了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>......침식체를 죽여. 침식체들을 증오해......! 전부 죽이는 거야......!!</color>","JPN":"<color=#ff3636>……侵食体を殺せ。侵食体を憎め……！すべて殺すんだ……！！</color>","ENG":"<color=#ff3636>Kill the C.O. Hate the C.O.! Kill them all!</color>","TWN":"<color=#ff3636>……殺掉侵蝕體，憎恨侵蝕體……！把他們全部殺掉……！！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>복수해. 전부 없애버리자.</color>","JPN":"<color=#ff3636>復讐しろ。すべて消してしまえ。</color>","ENG":"<color=#ff3636>Take revenge. Let's get rid of them all.</color>","TWN":"<color=#ff3636>我要報仇，我要讓他們通通消失。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"<color=#ff3636>없애버려!!!</color>","JPN":"<color=#ff3636>消してしまえ！！！</color>","ENG":"<color=#ff3636>Get rid of them all!</color>","TWN":"<color=#ff3636>消失吧！！！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"헉...... 헉......","JPN":"はあ……、はあ……","ENG":"*Pant* *Pant*","TWN":"哈……哈……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아, 오르카?","JPN":"大丈夫、オルカ？","ENG":"Are you okay, Orca?","TWN":"沒事吧，奧爾卡？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......또 그 <color=#ff3636>오르카</color>가 다른 숙주들의 기억을 보여준 거야?","JPN":"……また、その<color=#ff3636>オルカ</color>が、他の宿主の記憶を蘇らせたの？","ENG":"Did that <color=#ff3636>Orca</color> show you the memories of other hosts again?","TWN":"……<color=#ff3636>奧爾卡</color>又給妳看了其他宿主的記憶嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......응.","JPN":"……うん。","ENG":"Yeah.","TWN":"……嗯。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 녀석도 참 집요하구만.","JPN":"そいつ、本当にしつけえな。","ENG":"That's a persistent one.","TWN":"這傢伙可真是執著。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금처럼 의뢰를 받으면서 처치하는 것만으론 만족할 수 없단 건가?","JPN":"今みたいに、依頼を引き受けて倒すだけじゃ満足できないってのか？","ENG":"Is it not satisfied with just killing C.O. from our jobs?","TWN":"光靠現在委託的殺戮，他還是不能滿足嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......<color=#ff3636>오르카</color>는 한 번도 만족한 적 없어.","JPN":"……<color=#ff3636>オルカ</color>は一度も満足したことがないの。","ENG":"<color=#ff3636>Orca</color> has never been satisfied.","TWN":"……<color=#ff3636>奧爾卡</color>從來就沒有滿足過。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"항상 사냥에 굶주려있으니까. 다른 걸로 진정시키는 것뿐이야.","JPN":"いつも狩りに飢えてるから、他のもので落ち着かせてるだけ。","ENG":"It's always hungry for more hunts. I just calm it down by other means.","TWN":"它一直都渴望著獵殺，所以只能用其他事情讓他靜下來。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};